patch:
diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 00efd3c0eb72..a2f99a9121b9 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -7152,7 +7152,101 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
       if (foldValueComparisonIntoPredecessors(SI, Builder))
         return requestResimplify();
   }
+  if (auto *CB = dyn_cast<CallBase>(SI->getCondition())) {
+    if ((CB->getIntrinsicID() == Intrinsic::ucmp || CB->getIntrinsicID() == Intrinsic::scmp) && CB->hasOneUse()) {
+      BasicBlock *DestNeg1 = nullptr;
+      BasicBlock *Dest0 = nullptr;
+      BasicBlock *DestPos1 = nullptr;
+      BasicBlock *DefaultDest = SI->getDefaultDest();
+      
+      for (auto Case : SI->cases()) {
+        int64_t V = Case.getCaseValue()->getSExtValue();
+        if (V == -1) DestNeg1 = Case.getCaseSuccessor();
+        else if (V == 0) Dest0 = Case.getCaseSuccessor();
+        else if (V == 1) DestPos1 = Case.getCaseSuccessor();
+      }
+      
+      if (!DestNeg1) DestNeg1 = DefaultDest;
+      if (!Dest0) Dest0 = DefaultDest;
+      if (!DestPos1) DestPos1 = DefaultDest;
+      
+      BasicBlock *TrueDest = nullptr;
+      BasicBlock *FalseDest = nullptr;
+      ICmpInst::Predicate Pred;
+      bool IsUCmp = CB->getIntrinsicID() == Intrinsic::ucmp;
+      
+      if (Dest0 == DestPos1 && DestNeg1 != Dest0) {
+        Pred = IsUCmp ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_SLT;
+        TrueDest = DestNeg1;
+        FalseDest = Dest0;
+      } else if (DestNeg1 == Dest0 && DestPos1 != Dest0) {
+        Pred = IsUCmp ? ICmpInst::ICMP_UGT : ICmpInst::ICMP_SGT;
+        TrueDest = DestPos1;
+        FalseDest = Dest0;
+      }
+      
+      if (TrueDest) {
+        Builder.SetInsertPoint(SI);
+        Value *Cmp = Builder.CreateICmp(Pred, CB->getArgOperand(0), CB->getArgOperand(1));
+        
+        // Remove old switch edges
+        SmallPtrSet<BasicBlock*, 4> KeptSuccessors;
+        KeptSuccessors.insert(TrueDest);
+        KeptSuccessors.insert(FalseDest);
+        
+        // Remove incoming edges from successors that we no longer branch to.
+        for (unsigned i = 0, e = SI->getNumSuccessors(); i < e; ++i) {
+          BasicBlock *Succ = SI->getSuccessor(i);
+          if (!KeptSuccessors.count(Succ))
+            Succ->removePredecessor(SI->getParent());
+        }
+        
+        // Fix phi node edges for kept successors BEFORE replacing
+        for (BasicBlock *Succ : KeptSuccessors) {
+          int OldEdges = 0;
+          if (DefaultDest == Succ) OldEdges++;
+          for (auto Case : SI->cases())
+            if (Case.getCaseSuccessor() == Succ) OldEdges++;
+          
+          int NewEdges = (TrueDest == Succ ? 1 : 0) + (FalseDest == Succ ? 1 : 0);
+          
+          if (OldEdges > NewEdges) {
+            for (auto BBI = Succ->begin(); isa<PHINode>(BBI); ++BBI) {
+              for (int I = 0; I < OldEdges - NewEdges; ++I)
+                cast<PHINode>(BBI)->removeIncomingValue(SI->getParent());
+            }
+          }
+        }
+        
+        BranchInst *NewBI = Builder.CreateCondBr(Cmp, TrueDest, FalseDest);
+        
+        if (hasBranchWeightMD(*SI)) {
+          SmallVector<uint64_t, 8> Weights;
+          getBranchWeights(SI, Weights);
+          if (Weights.size() == 1 + SI->getNumCases()) {
+            uint64_t TrueWeight = 0;
+            uint64_t FalseWeight = 0;
+            for (size_t I = 0, E = Weights.size(); I != E; ++I) {
+              BasicBlock *Dest = (I == 0) ? DefaultDest : SI->getSuccessor(I);
+              if (Dest == TrueDest) TrueWeight += Weights[I];
+              else FalseWeight += Weights[I];
+            }
+            while (TrueWeight > UINT32_MAX || FalseWeight > UINT32_MAX) {
+              TrueWeight /= 2;
+              FalseWeight /= 2;
+            }
+            setBranchWeights(NewBI, TrueWeight, FalseWeight, /*IsExpected=*/false);
+          }
+        }
+        
+        SI->eraseFromParent();
+        CB->eraseFromParent();
+        return requestResimplify();
+      }
+    }
+  }

+  // 
   // Try to transform the switch into an icmp and a branch.
   // The conversion from switch to comparison may lose information on
   // impossible switch values, so disable it early in the pipeline.
